import{_ as a,o as i,c as e,a2 as t}from"./chunks/framework.CZqXuAiL.js";const c=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/getting-started/installation.md","filePath":"openshield-xdp/getting-started/installation.md","lastUpdated":1782454750000}'),n={name:"openshield-xdp/getting-started/installation.md"};function l(p,s,d,h,o,r){return i(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Linux kernel ≥ 5.8 (≥ 5.11 for freplace hot-patching)</li><li><code>CONFIG_DEBUG_INFO_BTF=y</code> in kernel config</li><li>XDP-capable NIC driver</li><li><code>clang</code> ≥ 12, <code>llvm</code>, <code>bpftool</code>, <code>libbpf-dev</code></li><li><code>Go</code> ≥ 1.21</li></ul><div class="tip custom-block"><p class="custom-block-title">Check BTF</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/kernel/btf/vmlinux</span></span></code></pre></div><p>If this file doesn&#39;t exist, your kernel was compiled without BTF support. Rebuild with <code>CONFIG_DEBUG_INFO_BTF=y</code>.</p></div><h2 id="one-liner-install" tabindex="-1">One-liner install <a class="header-anchor" href="#one-liner-install" aria-label="Permalink to &quot;One-liner install&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/AnAverageBeing/OpenShield-XDP/main/install-online.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bash</span></span></code></pre></div><p>Choose <strong>Install / Update</strong> from the menu. The installer auto-detects your package manager, installs dependencies, compiles BPF and Go, generates config, and sets up systemd.</p><h2 id="automated-install-from-clone" tabindex="-1">Automated install (from clone) <a class="header-anchor" href="#automated-install-from-clone" aria-label="Permalink to &quot;Automated install (from clone)&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/AnAverageBeing/OpenShield-XDP.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OpenShield-XDP</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./install.sh</span></span></code></pre></div><p>The installer auto-detects your package manager (apt, dnf, yum, pacman, apk, zypper), installs missing dependencies, compiles BPF and Go binaries, generates a default config, and sets up the systemd service. It runs <code>openshield fix</code> as a post-install step to clean any stale state.</p><h2 id="manual-build" tabindex="-1">Manual build <a class="header-anchor" href="#manual-build" aria-label="Permalink to &quot;Manual build&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vmlinux</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # Generate vmlinux.h from /sys/kernel/btf/vmlinux (first time only)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> all</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # BPF + bpf2go bindings + Go userspace</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><h2 id="verify-installation" tabindex="-1">Verify installation <a class="header-anchor" href="#verify-installation" aria-label="Permalink to &quot;Verify installation&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openshield</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bpftool</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prog</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> load</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /opt/openshield/lib/openshield.bpf.o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/fs/bpf/test_verify</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xdp</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sys/fs/bpf/test_verify</span></span></code></pre></div><p>Both commands should succeed. The verifier check confirms the BPF program is accepted by your kernel.</p><h2 id="update" tabindex="-1">Update <a class="header-anchor" href="#update" aria-label="Permalink to &quot;Update&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OpenShield-XDP</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./install.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --update</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The <code>--update</code> flag stops the running loader, replaces binaries and BPF object, then restarts. Existing bans survive across updates (pinned maps).</p></div><h2 id="uninstall" tabindex="-1">Uninstall <a class="header-anchor" href="#uninstall" aria-label="Permalink to &quot;Uninstall&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./install.sh</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --uninstall</span></span></code></pre></div><p>Removes binaries, systemd service, BPF pins, and socket files. Optionally preserves config and logs.</p><h2 id="supported-operating-systems" tabindex="-1">Supported operating systems <a class="header-anchor" href="#supported-operating-systems" aria-label="Permalink to &quot;Supported operating systems&quot;">​</a></h2><table tabindex="0"><thead><tr><th>OS</th><th>Package manager</th></tr></thead><tbody><tr><td>Ubuntu 22.04+</td><td>apt</td></tr><tr><td>Debian 12+</td><td>apt</td></tr><tr><td>Fedora 38+</td><td>dnf</td></tr><tr><td>RHEL 9 / Rocky / Alma</td><td>dnf / yum</td></tr><tr><td>Arch Linux</td><td>pacman</td></tr><tr><td>Alpine Linux</td><td>apk</td></tr><tr><td>openSUSE</td><td>zypper</td></tr></tbody></table><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/pingless-studios-docs/openshield-xdp/getting-started/quick-start">Quick Start</a> — load in under 30 seconds</li><li><a href="/pingless-studios-docs/openshield-xdp/user-guide/configuration">Configuration</a> — understand every YAML field</li></ul>`,25)])])}const u=a(n,[["render",l]]);export{c as __pageData,u as default};
